import{_ as t,a,b as n}from"./chunks/配置渠道内容.HzNkdrom.js";import{_ as s,o as i,c as o,a2 as d}from"./chunks/framework.DnrXFDHb.js";const k=JSON.parse('{"title":"Add a GitLab Packages Channel","description":"","frontmatter":{},"headers":[],"relativePath":"en/upload/gitlab-packages.md","filePath":"en/upload/gitlab-packages.md","lastUpdated":1781962217000}'),r={name:"en/upload/gitlab-packages.md"};function l(c,e,p,h,u,g){return i(),o("div",null,[...e[0]||(e[0]=[d('<h1 id="add-a-gitlab-packages-channel" tabindex="-1">Add a GitLab Packages Channel <a class="header-anchor" href="#add-a-gitlab-packages-channel" aria-label="Permalink to &quot;Add a GitLab Packages Channel&quot;">​</a></h1><h2 id="what-you-need-before-you-start" tabindex="-1">What You Need Before You Start <a class="header-anchor" href="#what-you-need-before-you-start" aria-label="Permalink to &quot;What You Need Before You Start&quot;">​</a></h2><p>You only need three things:</p><table tabindex="0"><thead><tr><th>Requirement</th><th>Purpose</th></tr></thead><tbody><tr><td>GitLab account</td><td>Used to generate an access token and own the project.</td></tr><tr><td>GitLab Personal Access Token</td><td>Used by ImgBed to access the GitLab API, create projects, and upload files to Generic Packages.</td></tr><tr><td>Project name</td><td>You can enter only the project name, for example <code>imgbed</code>.</td></tr></tbody></table><h2 id="setup-steps" tabindex="-1">Setup Steps <a class="header-anchor" href="#setup-steps" aria-label="Permalink to &quot;Setup Steps&quot;">​</a></h2><h3 id="step-1-sign-in-to-gitlab-and-create-an-access-token" tabindex="-1">Step 1: Sign in to GitLab and Create an Access Token <a class="header-anchor" href="#step-1-sign-in-to-gitlab-and-create-an-access-token" aria-label="Permalink to &quot;Step 1: Sign in to GitLab and Create an Access Token&quot;">​</a></h3><ol><li>Sign in to GitLab.</li><li>Click your avatar in the upper-right corner and open <code>Preferences</code>.</li><li>Open <code>Access Tokens</code> from the left sidebar.</li><li>Give the token a recognizable name.</li><li>Choose an expiration date based on your own maintenance preference.</li><li>Select the <code>api</code> scope.</li><li>Copy and save the token immediately after it is created.</li></ol><p><img src="'+t+'" alt="Create a legacy token" loading="lazy"></p><p><img src="'+a+'" alt="Select token permissions" loading="lazy"></p><h2 id="step-2-fill-in-the-gitlab-packages-channel-in-imgbed" tabindex="-1">Step 2: Fill in the GitLab Packages Channel in ImgBed <a class="header-anchor" href="#step-2-fill-in-the-gitlab-packages-channel-in-imgbed" aria-label="Permalink to &quot;Step 2: Fill in the GitLab Packages Channel in ImgBed&quot;">​</a></h2><p>After selecting <code>GitLab Packages</code> in Upload Settings, fill in the fields as follows:</p><table tabindex="0"><thead><tr><th>UI Field</th><th>What to Enter</th></tr></thead><tbody><tr><td>Channel name</td><td>A name you choose, such as <code>GitLabPrimary</code>.</td></tr><tr><td>Access Token</td><td>The GitLab Personal Access Token you just created.</td></tr><tr><td>Project name</td><td>Either a short project name such as <code>imgbed</code>, or a full path such as <code>username/imgbed</code>.</td></tr><tr><td>Private repository</td><td>Turn on or off based on your needs.</td></tr><tr><td>Remark</td><td>Optional, for example <code>Primary upload channel</code>.</td></tr></tbody></table><p><img src="'+n+`" alt="Configure the channel" loading="lazy"></p><h2 id="step-3-save-the-channel" tabindex="-1">Step 3: Save the Channel <a class="header-anchor" href="#step-3-save-the-channel" aria-label="Permalink to &quot;Step 3: Save the Channel&quot;">​</a></h2><p>After filling in the fields, click Save.</p><p>The system will handle these details:</p><table tabindex="0"><thead><tr><th>System Behavior</th><th>Description</th></tr></thead><tbody><tr><td>Short project name</td><td>ImgBed identifies the current GitLab account and expands the value into a full project path.</td></tr><tr><td>Full project path</td><td>ImgBed uses the <code>username/project</code> path exactly as entered.</td></tr><tr><td>Project check</td><td>If you use the current personal account path, ImgBed automatically creates the project when it does not exist. If you enter a full path manually, ImgBed uses that path directly.</td></tr><tr><td>Public/private state</td><td>Project visibility is synchronized according to the current switch.</td></tr></tbody></table><h2 id="quick-checklist" tabindex="-1">Quick Checklist <a class="header-anchor" href="#quick-checklist" aria-label="Permalink to &quot;Quick Checklist&quot;">​</a></h2><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Sign in to GitLab</span></span>
<span class="line"><span>-&gt; Create an Access Token</span></span>
<span class="line"><span>-&gt; Select only the api scope</span></span>
<span class="line"><span>-&gt; Return to ImgBed and enter the token and project name</span></span>
<span class="line"><span>-&gt; Save</span></span>
<span class="line"><span>-&gt; If only a project name is entered, ImgBed adds the current username automatically</span></span>
<span class="line"><span>-&gt; If username/project is entered, ImgBed uses it as-is</span></span>
<span class="line"><span>-&gt; Upload a test image</span></span></code></pre></div>`,19)])])}const f=s(r,[["render",l]]);export{k as __pageData,f as default};
